package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testParse_NullString_ThrowsException() {
        try (MockedStatic<Assertions> assertions = Mockito.mockStatic(Assertions.class)) {
            assertions.when(() -> Assertions.notNull(null, "string")).thenThrow(new NullPointerException("string"));
            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse((String) null, mockFormat);
            });
            assertEquals("string", thrown.getMessage());
        }
    }

    @Test
    void testParse_NullFormat_ThrowsException() {
        try (MockedStatic<Assertions> assertions = Mockito.mockStatic(Assertions.class)) {
            assertions.when(() -> Assertions.notNull("data", "format")).thenThrow(new NullPointerException("format"));
            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse("data", null);
            });
            assertEquals("format", thrown.getMessage());
        }
    }

    @Test
    void testParse_ValidInput_ReturnsCSVParser() throws IOException {
        String input = "a,b,c\n1,2,3";
        CSVParser parser = CSVParser.parse(input, mockFormat);
        assertNotNull(parser);
        // Check that parser is not closed initially
        assertFalse(parser.isClosed());
        // Check headerMap is initialized (may be null or map depending on CSVFormat mock)
        assertNotNull(parser.getHeaderMap());
        // Check record number starts at 0
        assertEquals(0L, parser.getRecordNumber());
    }
}
